import{c as o,Q as t,j as s,m as a}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"How do I route logins by email domain?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/portal/domain-login-rules.md","filePath":"guide/recipes/portal/domain-login-rules.md","lastUpdated":1778912818000}'),i={name:"guide/recipes/portal/domain-login-rules.md"};function r(l,e,n,d,c,h){return t(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="how-do-i-route-logins-by-email-domain" tabindex="-1">How do I route logins by email domain? <a class="header-anchor" href="#how-do-i-route-logins-by-email-domain" aria-label="Permalink to &quot;How do I route logins by email domain?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Owner</strong> or <strong>Admin</strong></p></div><p>Auth rules decide what happens when a user types their email at the sign-in screen — go to SSO, go to password, or offer both. They&#39;re matched by the email domain.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Settings → Security</strong>.</li><li>Scroll to <strong>Auth Rules</strong>.</li><li>Click <strong>Add Rule</strong>.</li><li>Fill in: <ul><li><strong>Domain</strong> — e.g. <code>acme.com</code> or <code>contractors.acme.com</code>.</li><li><strong>Method</strong> — <code>sso</code>, <code>password</code>, or <code>all</code>.</li><li><strong>Provider types</strong> (only when method is <code>sso</code>) — pick one or more IdPs to allow.</li></ul></li><li>Click <strong>Save</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>When a user signs in with an email matching the rule:</p><ul><li><code>sso</code> — they&#39;re redirected to the chosen IdP. The Console password screen is never shown.</li><li><code>password</code> — they go straight to the password screen, even if SSO is configured.</li><li><code>all</code> — they see a chooser with both options.</li></ul><div class="tip custom-block"><p class="custom-block-title">Order matters</p><p>Rules are evaluated top-to-bottom, longest-domain-first. A rule for <code>contractors.acme.com</code> wins over a rule for <code>acme.com</code> when both match.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./configure-sso">How do I configure SSO?</a></li></ul>',11)])])}const p=o(i,[["render",r]]);export{m as __pageData,p as default};
